// // This module counts down on each rising edge of the clock clk if reset is not asserted. If reset is asserted, the counter should be incremented to the maximum value.
module counter_4bit_sync_reset(
    input clk,
    input reset,

    output reg [3:0] count
);
    always @(posedge clk) begin
        if (reset)
            count <= 4'b0000;
        else
            count <= count + 1;
    end
endmodule
